content:
atches(';').trim();
        if rest.ends_with(';') && !name.is_empty() && name.chars().all(|c| c.is_alphanumeric() || c == '_') {
            Some(name)
        } else {
            None
        }
    }

    /// Compute a relative path from workspace root.
    fn relative_path(path: &Path, workspace_root: &Path) -> String {
        path.strip_prefix(workspace_root)
            .unwrap_or(path)
            .to_string_lossy()
            .into_owned()
    }
